// Helper function — get players by team slug
export function getPlayersByTeam(teamSlug) {
  return players.filter(p => p.teamSlug === teamSlug);
}

// Helper function — get single player by slug
export function getPlayerBySlug(slug) {
  return players.find(p => p.slug === slug);
}

// All player slugs — for generateStaticParams()
export const allPlayerSlugs = players.map(p => ({ slug: p.slug }));
